def get_icon(name: str, classes: str = "w-5 h-5") -> str:
    path = _ICONS.get(name, "")
    return f"""<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-{name} {classes}">{path}</svg>"""
